#
# Structure for table "crm_accounts"
#

CREATE TABLE `crm_accounts` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `type` enum('customer','partner') NOT NULL DEFAULT 'customer',
  `name` varchar(255) NOT NULL,
  `org_no` varchar(32) DEFAULT NULL,
  `reference` varchar(128) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `phone` varchar(64) DEFAULT NULL,
  `address1` varchar(255) DEFAULT NULL,
  `address2` varchar(255) DEFAULT NULL,
  `postal_code` varchar(16) DEFAULT NULL,
  `postal_city` varchar(128) DEFAULT NULL,
  `country` varchar(64) DEFAULT 'NO',
  `payment_terms_days` int NOT NULL DEFAULT '14',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_orgno` (`org_no`),
  KEY `idx_type` (`type`),
  KEY `idx_name` (`name`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

