#
# Structure for table "billing_invoice_drafts"
#

CREATE TABLE `billing_invoice_drafts` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `account_id` bigint unsigned NOT NULL,
  `status` enum('draft','locked','exported') NOT NULL DEFAULT 'draft',
  `title` varchar(255) DEFAULT NULL,
  `your_ref` varchar(128) DEFAULT NULL,
  `their_ref` varchar(128) DEFAULT NULL,
  `currency` char(3) NOT NULL DEFAULT 'NOK',
  `issue_date` date DEFAULT NULL,
  `due_date` date DEFAULT NULL,
  `notes` text,
  `subtotal` decimal(12,2) NOT NULL DEFAULT '0.00',
  `vat_amount` decimal(12,2) NOT NULL DEFAULT '0.00',
  `total` decimal(12,2) NOT NULL DEFAULT '0.00',
  `created_by` varchar(64) DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_account` (`account_id`),
