#
# Structure for table "nni_customers"
#

CREATE TABLE `nni_customers` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `customer_name` varchar(255) NOT NULL,
  `customer_ref` varchar(128) DEFAULT NULL,
  `product` varchar(128) DEFAULT NULL,
  `circuit_id` varchar(64) DEFAULT NULL,
  `street_address` varchar(255) DEFAULT NULL,
  `postal_code` varchar(16) DEFAULT NULL,
  `postal_city` varchar(128) DEFAULT NULL,
  `vendor_id` int unsigned NOT NULL,
  `service_router_id` int unsigned DEFAULT NULL,
  `edge_router_id` int unsigned DEFAULT NULL,
  `access_router_id` int unsigned DEFAULT NULL,
  `access_slot` varchar(32) DEFAULT NULL,
  `access_port` varchar(32) DEFAULT NULL,
  `cpe_mac` varchar(32) DEFAULT NULL,
  `cpe_type` varchar(64) DEFAULT NULL,
  `cpe_mgmt_ip_id` int unsigned DEFAULT NULL,
  `nni_vlan` int unsigned DEFAULT NULL,
  `c_vlan` int unsigned DEFAULT NULL,
  `bandwidth` varchar(64) DEFAULT NULL,
  `description` text,
  `status_install` tinyint(1) NOT NULL DEFAULT '0',
  `status_configured` tinyint(1) NOT NULL DEFAULT '0',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_nni_vendor` (`vendor_id`),
  KEY `idx_nni_sr` (`service_router_id`),
  KEY `idx_nni_er` (`edge_router_id`),
  KEY `idx_nni_ar` (`access_router_id`),
  KEY `idx_nni_cpe_mgmt_ip` (`cpe_mgmt_ip_id`),
  CONSTRAINT `fk_nni_ar_router` FOREIGN KEY (`access_router_id`) REFERENCES `access_routers` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_nni_cpe_mgmt_ip` FOREIGN KEY (`cpe_mgmt_ip_id`) REFERENCES `cpe_mgmt_ip` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_nni_er_router` FOREIGN KEY (`edge_router_id`) REFERENCES `edge_routers` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_nni_sr_router` FOREIGN KEY (`service_router_id`) REFERENCES `grossist_service_routers` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_nni_vendor` FOREIGN KEY (`vendor_id`) REFERENCES `grossist_vendors` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

#
