#
# Structure for table "inv_batches"
#

CREATE TABLE `inv_batches` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `product_id` int unsigned NOT NULL,
  `physical_location_id` int unsigned DEFAULT NULL,
  `project_id` bigint unsigned DEFAULT NULL,
  `received_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `supplier` varchar(128) DEFAULT NULL,
  `note` varchar(255) DEFAULT NULL,
  `unit_price` decimal(12,4) NOT NULL DEFAULT '0.0000',
  `qty_received` decimal(12,3) NOT NULL DEFAULT '0.000',
  `qty_remaining` decimal(12,3) NOT NULL DEFAULT '0.000',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `invoice_received` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_product_remaining` (`product_id`,`qty_remaining`),
  KEY `idx_received_at` (`received_at`),
  KEY `idx_phys` (`physical_location_id`),
  KEY `idx_proj` (`project_id`),
  CONSTRAINT `fk_invbatch_phys` FOREIGN KEY (`physical_location_id`) REFERENCES `inv_locations` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_invbatch_product` FOREIGN KEY (`product_id`) REFERENCES `inv_products` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_invbatch_project` FOREIGN KEY (`project_id`) REFERENCES `projects` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

