#

CREATE TABLE `billing_invoice_lines` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `invoice_id` bigint unsigned NOT NULL,
  `line_no` int NOT NULL DEFAULT '1',
  `line_type` enum('PRODUCT','SERVICE','MANUAL') NOT NULL DEFAULT 'PRODUCT',
  `product_id` int unsigned DEFAULT NULL,
  `batch_id` bigint unsigned DEFAULT NULL,
  `work_order_id` bigint unsigned DEFAULT NULL,
  `project_id` bigint unsigned DEFAULT NULL,
  `description` varchar(255) NOT NULL,
  `unit` varchar(32) NOT NULL DEFAULT 'stk',
  `qty` decimal(12,3) NOT NULL DEFAULT '1.000',
  `cost_unit` decimal(12,4) NOT NULL DEFAULT '0.0000',
  `cost_total` decimal(12,2) NOT NULL DEFAULT '0.00',
  `markup_pct` decimal(8,2) DEFAULT NULL,
  `sell_unit` decimal(12,4) NOT NULL DEFAULT '0.0000',
  `sell_total` decimal(12,2) NOT NULL DEFAULT '0.00',
  `vat_rate` decimal(5,2) NOT NULL DEFAULT '0.00',
  `vat_amount` decimal(12,2) NOT NULL DEFAULT '0.00',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_invoice` (`invoice_id`),
  KEY `idx_product` (`product_id`),
  KEY `idx_project` (`project_id`),
  KEY `idx_workorder` (`work_order_id`),
  KEY `fk_line_batch` (`batch_id`),
  CONSTRAINT `fk_line_batch` FOREIGN KEY (`batch_id`) REFERENCES `inv_batches` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_line_invoice` FOREIGN KEY (`invoice_id`) REFERENCES `billing_invoice_drafts` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_line_product` FOREIGN KEY (`product_id`) REFERENCES `inv_products` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_line_project` FOREIGN KEY (`project_id`) REFERENCES `projects` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_line_workorder` FOREIGN KEY (`work_order_id`) REFERENCES `work_orders` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

