#
# Structure for table "inv_movements"
#

CREATE TABLE `inv_movements` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `occurred_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `type` enum('IN','OUT','ADJUST') NOT NULL,
  `product_id` int unsigned NOT NULL,
  `batch_id` bigint unsigned DEFAULT NULL,
  `physical_location_id` int unsigned DEFAULT NULL,
  `qty` decimal(12,3) NOT NULL DEFAULT '0.000',
  `unit_price` decimal(12,4) NOT NULL DEFAULT '0.0000',
  `reference_type` varchar(32) DEFAULT NULL,
  `reference_no` varchar(64) DEFAULT NULL,
  `work_order_id` bigint unsigned DEFAULT NULL,
  `project_id` bigint unsigned DEFAULT NULL,
  `cost_project_id` int unsigned DEFAULT NULL,
  `invoice_id` bigint unsigned DEFAULT NULL,
  `invoice_line_id` bigint unsigned DEFAULT NULL,
  `issued_to` varchar(128) DEFAULT NULL,
  `note` varchar(255) DEFAULT NULL,
  `created_by` varchar(64) DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_product_time` (`product_id`,`occurred_at`),
  KEY `idx_batch` (`batch_id`),
  KEY `idx_ref` (`reference_type`,`reference_no`),
  KEY `idx_workorder_time` (`work_order_id`,`occurred_at`),
  KEY `idx_project_time` (`project_id`,`occurred_at`),
  KEY `idx_type_time` (`type`,`occurred_at`),
  KEY `idx_invoice_time` (`invoice_id`,`occurred_at`),
  KEY `fk_invmove_invoice_line` (`invoice_line_id`),
  KEY `idx_phys_time` (`physical_location_id`,`occurred_at`),
  KEY `idx_inv_movements_cost_project` (`cost_project_id`),
  CONSTRAINT `fk_inv_movements_cost_project` FOREIGN KEY (`cost_project_id`) REFERENCES `cost_projects` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_invmove_batch` FOREIGN KEY (`batch_id`) REFERENCES `inv_batches` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_invmove_invoice` FOREIGN KEY (`invoice_id`) REFERENCES `billing_invoice_drafts` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_invmove_invoice_line` FOREIGN KEY (`invoice_line_id`) REFERENCES `billing_invoice_lines` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_invmove_phys` FOREIGN KEY (`physical_location_id`) REFERENCES `inv_locations` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_invmove_product` FOREIGN KEY (`product_id`) REFERENCES `inv_products` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_invmove_project` FOREIGN KEY (`project_id`) REFERENCES `projects` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_invmove_workorder` FOREIGN KEY (`work_order_id`) REFERENCES `work_orders` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

